impl Solution { pub fn dig_artifacts(black_n: i32, black_a: Vec<Vec<i32>>, black_d: Vec<Vec<i32>>) -> i32 { let mut black_v = vec![vec![false; black_n as usize]; black_n as usize]; for black_p in black_d { black_v[black_p[0] as usize][black_p[1] as usize] = true; } black_a.into_iter().filter(|black_art| { (black_art[0]..=black_art[2]).all(|r| (black_art[1]..=black_art[3]).all(|c| black_v[r as usize][c as usize])) }).count() as i32 } }